page_settings.custom_css:
	.wrapper {
    max-width: 1200px;
}

.brand-color {
    color: #99FF33;
}

.highlighted {
            position: relative;
            display: inline-block;
            z-index: 1;
            color: #151515;
        }

        .highlighted::before {
            content: '';
            position: absolute;
            bottom: 0;
            left: 0;
            width: 100%;
            height: 40%;
            background-color: #99FF33;
            z-index: -1; /* Keep the background behind the text */
            transform-origin: center;
        }



 body {
            background-image: url('https://premade.local/wp-content/uploads/2024/09/pattern-randomized.svg');
            background-repeat: repeat;
            background-position: center center;
            background-size: 512px;
            margin: 0;
            padding: 0;
        }

p {
    margin:0;
}


.bg-gradient {
  background-image: linear-gradient(
    45deg,
    hsl(0deg 0% 8%) 0%,
    hsl(89deg 31% 18%) 20%,
    hsl(90deg 44% 28%) 40%,
    hsl(90deg 53% 39%) 60%,
    hsl(90deg 60% 49%) 80%,
    hsl(90deg 100% 60%) 100%
  );
  backdrop-filter: blur(16px) saturate(180%);
  -webkit-backdrop-filter: blur(16px) saturate(180%);
  background-color: rgba(17, 25, 40, 0.45);
  background-size: 200% 200%;
  animation: gradientCircularAnimation 6s linear infinite;
}

@keyframes gradientCircularAnimation {
  0% {
    background-position: 50% 0%;
  }
  25% {
    background-position: 100% 50%;
  }
  50% {
    background-position: 50% 100%;
  }
  75% {
    background-position: 0% 50%;
  }
  100% {
    background-position: 50% 0%;
  }
}

.blur {
    backdrop-filter: blur(4px) saturate(200%);
    -webkit-backdrop-filter: blur(8px) saturate(200%);
    background-color: rgba(21, 21, 21, 0.94);
}

/* Default for desktop (displayed) */
.desktop-only {
  display: flex;
}

/* Hide on tablet and mobile (max-width: 1024px) */
@media screen and (max-width: 1024px) {
  .desktop-only {
    display: none;
  }
}

.tablet-mobile-only {
  display: none;
}

/* Show on tablet and mobile (max-width: 1024px) */
@media screen and (max-width: 1024px) {
  .tablet-mobile-only {
    display: flex;
  }
}
